  totalTests: number;
  totalPassed: number;
  totalFailed: number;
  totalSkipped: number;
  totalDuration: number; // in milliseconds
  suites: TestSuite[];
  flakyTests: FlakyTest[];
}

export interface FlakyTest {
  name: string;
  className: string;
  failureCount: number;
  passageCount: number;
  runIds: string[];
}

export interface ParsedResults {
  format: 'junit' | 'json';
  runId: string;
  results: TestSuite[];
}

