import { TestSuite, ParsedResults, TestCase } from './types';

// Parse JUnit XML format test results
export function parseJunitXml(xmlContent: string, runId: string): ParsedResults {
  const results: TestSuite[] = [];

  // Simple XML parsing: find <testsuite> elements
  const suiteRegex = /<testsuite[^>]*name="([^"]*)"[^>]*tests="(\d+)"[^>]*failures="(\d+)"[^>]*skipped="(\d+)"[^>]*time="([^"]*)"/g;
  const caseRegex = /<testcase[^>]*classname="([^"]*)"[^>]*name="([^"]*)"[^>]*time="([^"]*)"\s*\/?>/g;
  const failureRegex = /<testcase[^>]*classname="([^"]*)"[^>]*name="([^"]*)"[^>]*time="([^"]*)"\s*>[\s\S]*?<failure[^>]*message="([^"]*)"[\s\S]*?<\/testcase>/g;
  const skippedRegex = /<testcase[^>]*classname="([^"]*)"[^>]*name="([^"]*)"[^>]*time="([^"]*)"\s*>[\s\S]*?<skipped[\s\S]*?<\/testcase>/g;

  let suiteMatch;
  const suiteMatches = Array.from(xmlContent.matchAll(suiteRegex));

  for (const suiteMatch of suiteMatches) {
    const suiteName = suiteMatch[1];
    const testCount = parseInt(suiteMatch[2], 10);
    const failureCount = parseInt(suiteMatch[3], 10);
    const skippedCount = parseInt(suiteMatch[4], 10);
    const time = parseFloat(suiteMatch[5]);

    const cases: TestCase[] = [];

    // Find testcases for this suite
    const caseMatches = Array.from(xmlContent.matchAll(caseRegex));
    const failureMatches = Array.from(xmlContent.matchAll(failureRegex));
    const skippedMatches = Array.from(xmlContent.matchAll(skippedRegex));

    const failedTestNames = new Set(failureMatches.map(m => `${m[1]}::${m[2]}`));
    const skippedTestNames = new Set(skippedMatches.map(m => `${m[1]}::${m[2]}`));

    for (const caseMatch of caseMatches) {
      const className = caseMatch[1];
      const testName = caseMatch[2];
      const duration = parseFloat(caseMatch[3]) * 1000; // Convert to ms

      let status: 'passed' | 'failed' | 'skipped' = 'passed';
      let message: string | undefined;

      const testKey = `${className}::${testName}`;
      if (failedTestNames.has(testKey)) {
        status = 'failed';
        const failedMatch = Array.from(xmlContent.matchAll(failureRegex)).find(
          m => m[1] === className && m[2] === testName
        );
        if (failedMatch) {
          message = failedMatch[4];
        }
      } else if (skippedTestNames.has(testKey)) {
        status = 'skipped';
      }

      cases.push({
        name: testName,
        className,
        status,
        duration,
        message,
        runId,
      });
    }

    results.push({
      name: suiteName,
      tests: testCount,
      failures: failureCount,
      skipped: skippedCount,
      time,
      cases,
    });
  }

  return {
    format: 'junit',
    runId,
    results,
  };
}

// Parse JSON format test results
export function parseJsonResults(jsonContent: string, runId: string): ParsedResults {
  const jsonData = JSON.parse(jsonContent);

  const results: TestSuite[] = jsonData.suites.map((suite: any) => {
    const cases: TestCase[] = suite.cases.map((testCase: any) => ({
      name: testCase.name,
      className: testCase.className,
      status: testCase.status,
      duration: testCase.duration,
      message: testCase.message,
      runId,
    }));

    return {
      name: suite.name,
      tests: suite.tests,
      failures: suite.failures,
      skipped: suite.skipped,
      time: suite.time,
      cases,
    };
  });

  return {
    format: 'json',
    runId,
    results,
  };
}

