function getAttr(attrs: string, name: string): string | undefined {
  const match = attrs.match(new RegExp(`${name}="([^"]*)"`));
  return match ? match[1] : undefined;
}

// Parse JUnit XML format test results
export function parseJunitXml(xmlContent: string, runId: string): ParsedResults {
  const results: TestSuite[] = [];

  // Extract suite content and metadata
  const suiteRegex = /<testsuite\s+([^>]*)>([\s\S]*?)<\/testsuite>/g;

  let suiteMatch;
  while ((suiteMatch = suiteRegex.exec(xmlContent)) !== null) {
    const attrs = suiteMatch[1];
    const suiteContent = suiteMatch[2];

    // Parse suite attributes
    const suiteName = getAttr(attrs, 'name') || 'Unknown';
    const testCount = parseInt(getAttr(attrs, 'tests') || '0', 10);
    const failureCount = parseInt(getAttr(attrs, 'failures') || '0', 10);
    const skippedCount = parseInt(getAttr(attrs, 'skipped') || '0', 10);
    const time = parseFloat(getAttr(attrs, 'time') || '0');

    const cases: TestCase[] = [];

    // Find all opening testcase tags and their content
    const caseRegex = /<testcase\s+([^>]*)(?:\s*(\/>)|>([\s\S]*?)<\/testcase>)/g;

    let caseMatch;
    while ((caseMatch = caseRegex.exec(suiteContent)) !== null) {
      const caseAttrs = caseMatch[1];
      const isSelfClosing = !!caseMatch[2];
      const caseBody = caseMatch[3] || '';

      const className = getAttr(caseAttrs, 'classname') || 'Unknown';
      const testName = getAttr(caseAttrs, 'name') || 'Unknown';
      const duration = parseFloat(getAttr(caseAttrs, 'time') || '0') * 1000;

      let status: 'passed' | 'failed' | 'skipped' = 'passed';
      let message: string | undefined;

      if (caseBody.includes('<failure')) {
        status = 'failed';
        message = getAttr(caseBody, 'message');
